/**
 * Material Symbols Rounded font set identifier
 *
 * @remarks
 * Corresponds to the CSS class generated by the Google Fonts stylesheet for
 * the Rounded variant. The active value must match the font family loaded in
 * the application (e.g., via a `<link>` tag in `index.html`).
 *
 * @see {@link https://fonts.google.com/icons | Google Material Symbols}
 *
 * @category Constants
 * @displayName Font Set: Rounded
 * @order 1
 * @since 1.0.0
 * @related TbxMatFontIconService
 * @related TBX_MAT_FONT_ICON_DEFAULT_FONT_SET
 *
 * @public
 */
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_ROUNDED = 'material-symbols-rounded';

